import type { Theme } from "@t3tools/shared/themes";
import { cn } from "~/lib/utils";
import { useTheme } from "./ThemeProvider";

function ThemeSwatch({ t }: { t: Theme }) {
  return (
    <div
      className="h-10 w-full overflow-hidden rounded-lg border border-black/10"
      style={{ background: t.colors.background }}
      aria-hidden="true"
    >
      <div className="flex h-full">
        {/* Sidebar strip */}
        <div className="w-[28%]" style={{ background: t.colors.sidebar }} />
        {/* Main area */}
        <div className="flex flex-1 flex-col">
          {/* Status bar */}
          <div className="h-2 shrink-0" style={{ background: t.colors.statusBar }} />
          {/* Editor body with mock code lines */}
          <div className="flex-1 px-1.5 pt-1.5" style={{ background: t.colors.editor }}>
            <div className="space-y-1">
              <div
                className="h-1 w-3/4 rounded-full opacity-50"
                style={{ background: t.colors.accent }}
              />
              <div
                className="h-1 w-1/2 rounded-full opacity-30"
                style={{ background: t.colors.foreground }}
              />
              <div
                className="h-1 w-2/3 rounded-full opacity-20"
                style={{ background: t.colors.foreground }}
              />
            </div>
          </div>
          {/* Terminal strip */}
          <div className="h-[28%] shrink-0" style={{ background: t.colors.terminal }} />
        </div>
      </div>
    </div>
  );
}

interface ThemeSelectorProps {
  className?: string;
}

/**
 * Grid of theme cards with color swatches. Must be rendered inside `<ThemeProvider>`.
 */
export function ThemeSelector({ className }: ThemeSelectorProps) {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div
      className={cn("grid grid-cols-1 gap-2 sm:grid-cols-3", className)}
      role="radiogroup"
      aria-label="Color theme"
    >
      {availableThemes.map((t) => {
        const selected = theme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={cn(
              "flex flex-col gap-2 rounded-xl border px-3 py-3 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 ring-1 ring-primary/20"
                : "border-border bg-background hover:bg-accent",
            )}
            onClick={() => setTheme(t.id)}
          >
            <ThemeSwatch t={t} />
            <div className="flex items-center justify-between gap-2">
              <span className="text-sm font-medium text-foreground">{t.name}</span>
              {selected && (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}

