  const raw = localStorage.getItem(STORAGE_KEY);
  // Validate that the stored id is a real theme; fall back to default otherwise.
  if (raw && getTheme(raw).id === raw) return raw;
  return DEFAULT_THEME_ID;
}

// getTheme always returns the same object reference for the same id (Map lookup),
// so useSyncExternalStore reference stability is satisfied without extra caching.
function getSnapshot(): Theme {
  return getTheme(getStoredId());
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync theme across tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) emitChange();
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// CSS variable application
// ---------------------------------------------------------------------------

const COLOR_CSS_VARS: Record<keyof Theme["colors"], string> = {
  background: "--t-background",
  foreground: "--t-foreground",
  accent: "--t-accent",
  sidebar: "--t-sidebar",
  editor: "--t-editor",
  terminal: "--t-terminal",
  statusBar: "--t-status-bar",
};

function applyThemeVars(theme: Theme, suppressTransitions = false): void {
  const root = document.documentElement;
  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }
  for (const [key, cssVar] of Object.entries(COLOR_CSS_VARS) as Array<
    [keyof Theme["colors"], string]
  >) {
    root.style.setProperty(cssVar, theme.colors[key]);
  }
  root.style.setProperty("--t-font-family", theme.fontFamily);
  root.style.setProperty("--t-font-size", `${theme.fontSize}px`);
  if (suppressTransitions) {
    // Force a reflow so no-transitions takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent a flash of un-themed UI.
applyThemeVars(getTheme(getStoredId()));

// ---------------------------------------------------------------------------
// React context + provider
// ---------------------------------------------------------------------------

const ThemeContext = createContext<CustomThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyThemeVars(next, true);
    emitChange();
  }, []);

  // Keep CSS vars in sync whenever the theme changes (e.g. cross-tab storage event).
  useEffect(() => {
    applyThemeVars(theme);
  }, [theme]);

  const value = useMemo<CustomThemeContextValue>(
    () => ({ theme, setTheme, availableThemes: listThemes() }),
    [theme, setTheme],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

/**
 * Access the current custom color theme.
 *
 * Must be rendered inside `<ThemeProvider>`.
 */
export function useTheme(): CustomThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return ctx;
}
